const inp = $input.first().json;
const op = String(inp.operation || '').trim();
let p = inp.params;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { p = {}; } }
p = p || {};
const nowIso = new Date().toISOString();
const esc = (s) => String(s || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const nameRx = (s) => ({ $regex: esc(String(s).trim()).split(/\s+/).join('.*'), $options: 'i' });
const last10 = (v) => String(v || '').replace(/\D/g, '').slice(-10);
const pad = (n) => ('0' + n).slice(-2);
const normDob = (v) => {
  const s = String(v || '').trim();
  let m = s.match(/^(\d{4})[-\/](\d{1,2})[-\/](\d{1,2})$/);
  if (m) return m[1] + '-' + pad(m[2]) + '-' + pad(m[3]);
  m = s.match(/^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})$/);
  if (m) return m[3] + '-' + pad(m[2]) + '-' + pad(m[1]);
  return s;
};
const out = (o) => [{ json: o }];
const err = (m) => out({ __kind: 'error', __error: m });
const mkId = (pre) => pre + '-' + Date.now().toString(36).toUpperCase() + '-' + Math.floor(10 + Math.random() * 90);

if (op === 'find_client') {
  const q = {};
  if (p.phoneLast10) q.phoneLast10 = last10(p.phoneLast10);
  if (p.name) q.name = nameRx(p.name);
  if (p.dob) q.dob = normDob(p.dob);
  if (!Object.keys(q).length) return err('find_client needs name or phoneLast10');
  return out({ __kind: 'find', __collection: 'clients', __query: q, __limit: 6, __sort: {} });
}
if (op === 'get_policies') {
  const q = {};
  if (p.policyNo) q.policyNo = { $regex: esc(p.policyNo), $options: 'i' };
  else if (p.phoneLast10) q.phoneLast10 = last10(p.phoneLast10);
  else if (p.clientName) q.clientName = nameRx(p.clientName);
  else return err('get_policies needs clientName, phoneLast10 or policyNo');
  return out({ __kind: 'find', __collection: 'policies', __query: q, __limit: 20, __sort: {} });
}
if (op === 'get_ticket') {
  if (!p.ticketId) return err('get_ticket needs ticketId');
  return out({ __kind: 'find', __collection: 'tickets', __query: { ticketId: String(p.ticketId) }, __limit: 1, __sort: {} });
}
if (op === 'get_claim') {
  if (!p.claimId) return err('get_claim needs claimId');
  return out({ __kind: 'find', __collection: 'claims', __query: { claimId: String(p.claimId) }, __limit: 1, __sort: {} });
}
if (op === 'ticket_guard') {
  const q = { state: { $nin: ['closed', 'resolved'] } };
  if (p.category) q.category = String(p.category);
  if (p.clientName) q.clientName = nameRx(p.clientName);
  if (p.phoneLast10) q.phoneLast10 = last10(p.phoneLast10);
  if (!p.clientName && !p.phoneLast10) return err('ticket_guard needs clientName or phoneLast10');
  return out({ __kind: 'find', __collection: 'tickets', __query: q, __limit: 5, __sort: { createdAt: -1 } });
}
if (op === 'paginate') {
  const page = Math.max(1, parseInt(p.page || 1, 10) || 1);
  if (p.type === 'leads') {
    const q = { status: p.status || 'active' };
    if (p.stage) q.stage = String(p.stage);
    return out({ __kind: 'find', __collection: 'leads', __query: q, __limit: 5, __skip: (page - 1) * 5, __sort: { createdAt: -1 }, __projection: { name: 1, phone: 1, interest: 1, stage: 1, status: 1, referredBy: 1, createdAt: 1 }, __page: page });
  }
  if (p.type === 'claims') {
    const q = { status: p.status || 'pending' };
    if (p.phoneLast10) q.phoneLast10 = last10(p.phoneLast10);
    if (p.clientName) q.clientName = nameRx(p.clientName);
    return out({ __kind: 'find', __collection: 'claims', __query: q, __limit: 5, __skip: (page - 1) * 5, __sort: { createdAt: -1 }, __page: page });
  }
  if (p.type === 'tickets') {
    const q = {};
    if (p.state) q.state = p.state; else q.state = { $nin: ['closed'] };
    if (p.phoneLast10) q.phoneLast10 = last10(p.phoneLast10);
    if (p.clientName) q.clientName = nameRx(p.clientName);
    return out({ __kind: 'find', __collection: 'tickets', __query: q, __limit: 5, __skip: (page - 1) * 5, __sort: { createdAt: -1 }, __page: page });
  }
  return err('paginate needs type leads | claims | tickets');
}
if (op === 'crm_list') {
  const page = Math.max(1, parseInt(p.page || 1, 10) || 1);
  const t = String(p.type || '');
  const d = new Date();
  const mm = pad(p.month || (d.getMonth() + 1));
  const dd = p.day ? pad(p.day) : null;
  const yr = String(p.year || d.getFullYear());
  if (t === 'birthday' || t === 'anniversary') {
    const field = t === 'birthday' ? 'dob' : 'anniversary';
    const rx = dd ? ('-' + mm + '-' + dd + '$') : ('-' + mm + '-');
    const q = {}; q[field] = { $regex: rx };
    return out({ __kind: 'find', __collection: 'clients', __query: q, __limit: 30, __skip: (page - 1) * 30, __sort: {}, __projection: { name: 1, dob: 1, anniversary: 1, phone: 1, phoneLast10: 1 }, __page: page });
  }
  if (t === 'maturity') {
    return out({ __kind: 'find', __collection: 'clients', __query: { maturityDate: { $regex: '^' + yr + '-' + mm }, isActive: { $ne: false } }, __limit: 60, __sort: { maturityDate: 1 }, __projection: { name: 1, policyNo: 1, sumAssured: 1, maturityDate: 1, phone: 1, tableNo: 1 }, __page: page });
  }
  if (t === 'dues') {
    return out({ __kind: 'find', __collection: 'clients', __query: { fupDate: { $regex: '^' + yr + '-' + mm }, isActive: { $ne: false } }, __limit: 60, __sort: { fupDate: 1 }, __projection: { name: 1, policyNo: 1, premium: 1, mode: 1, fupDate: 1, phone: 1 }, __page: page });
  }
  if (t === 'clients') {
    if (p.countOnly) return out({ __kind: 'counts', __collection: 'clients', __query: {}, __limit: 100000, __type: 'clients', __groupField: 'isActive', __projection: { isActive: 1 } });
    const q = p.withPhone ? { phoneLast10: { $exists: true, $nin: [null, ''] } } : {};
    return out({ __kind: 'find', __collection: 'clients', __query: q, __limit: Math.min(10, parseInt(p.limit || 10, 10) || 10), __skip: (page - 1) * 10, __sort: { name: 1 }, __projection: { name: 1, phone: 1, phoneLast10: 1 }, __page: page });
  }
  return err('crm_list type must be birthday | anniversary | maturity | dues | clients');
}
if (op === 'team_ops') {
  const a = String(p.action || '');
  if (a === 'list') return out({ __kind: 'find', __collection: 'team_members', __query: { active: { $ne: false } }, __limit: 20, __sort: { name: 1 } });
  if (a === 'assign' || a === 'meeting') {
    if (!p.title) return err('team_ops needs title (what is the task/meeting about)');
    if (a === 'assign' && !p.assigneeName && !p.assigneePhone) return err('assign needs assigneeName or assigneePhone. Call team_ops {"action":"list"} to see team members.');
    const doc = {
      taskId: mkId('CGPE-TASK'), type: a === 'meeting' ? 'meeting' : 'task',
      title: String(p.title), details: String(p.details || ''),
      assigneeName: String(p.assigneeName || p.createdBy || 'CGPE Admin'), assigneePhone: last10(p.assigneePhone || ''),
      ticketId: String(p.ticketId || ''), clientName: String(p.clientName || ''), clientPhone: last10(p.clientPhone || ''),
      dueAt: String(p.dueAt || ''), priority: String(p.priority || 'P3'), status: 'open',
      createdBy: String(p.createdBy || 'admin'), createdAt: nowIso, updatedAt: nowIso
    };
    return out({ __kind: 'insert', __collection: 'team_tasks', __fields: Object.keys(doc).join(','), ...doc });
  }
  if (a === 'tasks') {
    const q = { status: { $ne: 'done' } };
    if (p.assigneeName) q.assigneeName = nameRx(p.assigneeName);
    if (p.today) q.$or = [{ dueAt: { $regex: '^' + nowIso.slice(0, 10) } }, { dueAt: '' }];
    return out({ __kind: 'find', __collection: 'team_tasks', __query: q, __limit: 20, __sort: { dueAt: 1 } });
  }
  if (a === 'complete') {
    if (!p.taskId) return err('complete needs taskId');
    return out({ __kind: 'update', __collection: 'team_tasks', __updateKey: 'taskId', __fields: 'status,updatedAt', taskId: String(p.taskId), status: 'done', updatedAt: nowIso });
  }
  return err('team_ops action must be list | assign | meeting | tasks | complete');
}
if (op === 'create_lead') {
  if (!p.name) return err('create_lead needs name');
  const doc = {
    leadId: mkId('CGPE-L'), name: String(p.name).toUpperCase(), phone: String(p.phone || ''), phoneLast10: last10(p.phone || ''),
    interest: String(p.interest || 'general'), stage: 'new', status: 'active',
    source: String(p.source || 'whatsapp'), referredBy: String(p.referredBy || ''), notes: String(p.notes || ''),
    createdAt: nowIso, updatedAt: nowIso
  };
  return out({ __kind: 'insert', __collection: 'leads', __fields: Object.keys(doc).join(','), ...doc });
}
if (op === 'get_documents') {
  const q = { };
  if (p.policyNo) q.policyNo = { $regex: esc(p.policyNo), $options: 'i' };
  else if (p.phoneLast10) q.phoneLast10 = last10(p.phoneLast10);
  else if (p.clientName) q.clientName = nameRx(p.clientName);
  else return err('get_documents needs clientName, phoneLast10 or policyNo');
  return out({ __kind: 'find', __collection: 'policy_documents', __query: q, __limit: 10, __sort: { createdAt: -1 } });
}
if (op === 'create_ticket') {
  if (!p.category || !p.aiUnderstanding || !p.task) return err('create_ticket needs category, aiUnderstanding, task');
  if (!p.clientName && !p.phoneLast10) return err('create_ticket needs clientName or phoneLast10');
  const doc = {
    ticketId: mkId('CGPE-T'), category: String(p.category), kind: String(p.kind || 'general'),
    state: 'new', priority: String(p.priority || 'P3'), zone: String(p.zone || 'amber'),
    clientName: String(p.clientName || ''), phoneLast10: last10(p.phoneLast10 || ''), policyNo: String(p.policyNo || ''),
    originalCommand: String(p.originalCommand || ''), aiUnderstanding: String(p.aiUnderstanding), task: String(p.task),
    requiredItems: Array.isArray(p.requiredItems) ? p.requiredItems : [], receivedItems: [],
    slots: (typeof p.slots === 'object' && p.slots) || {}, source: String(p.source || 'admin'), channel: 'whatsapp',
    assignedTo: String(p.assignedTo || ''),
    audit: [{ ts: nowIso, actor: 'ai', action: 'created' }], createdAt: nowIso, updatedAt: nowIso
  };
  return out({ __kind: 'insert', __collection: 'tickets', __fields: Object.keys(doc).join(','), ...doc });
}
if (op === 'create_claim') {
  if (!p.claimType) return err('create_claim needs claimType (health | general | motor | life | death | maturity)');
  if (!p.policyNo) return err('create_claim needs policyNo');
  if (!p.clientName) return err('create_claim needs clientName');
  const slots = (typeof p.slots === 'object' && p.slots) || {};
  const reqByType = {
    health: ['hospitalName', 'patientName', 'admitDate', 'illness', 'doctorName'],
    general: ['policyType', 'cause', 'date'],
    motor: ['policyType', 'cause', 'date'],
    life: ['patientName', 'date', 'cause'],
    death: ['patientName', 'date', 'cause']
  };
  const req = reqByType[String(p.claimType)] || [];
  const missing = req.filter((k) => !slots[k]);
  if (missing.length) return err('Cannot create ' + p.claimType + ' claim yet. Missing slots: ' + missing.join(', ') + '. Ask the sender for these first.');
  const doc = {
    claimId: mkId('CGPE-C'), ticketId: String(p.ticketId || ''), claimType: String(p.claimType),
    clientName: String(p.clientName), phoneLast10: last10(p.phoneLast10 || ''), policyNo: String(p.policyNo),
    stage: 'documents_required', status: 'pending', slots,
    amounts: { claimed: null, approved: null, received: null, shortfall: null },
    statusHistory: [{ stage: 'documents_required', at: nowIso, actor: 'ai' }],
    createdAt: nowIso, updatedAt: nowIso
  };
  return out({ __kind: 'insert', __collection: 'claims', __fields: Object.keys(doc).join(','), ...doc });
}
if (op === 'update_ticket') {
  if (!p.ticketId) return err('update_ticket needs ticketId');
  const set = (typeof p.set === 'object' && p.set) || {};
  const allowed = ['state', 'priority', 'zone', 'task', 'aiUnderstanding', 'requiredItems', 'receivedItems', 'slots', 'policyNo', 'lastNote', 'assignedTo'];
  const states = ['new', 'info_pending', 'in_progress', 'awaiting_third_party', 'escalated', 'resolved', 'closed'];
  if (set.state && !states.includes(set.state)) return err('Invalid state. Valid: ' + states.join(', '));
  const doc = { ticketId: String(p.ticketId), updatedAt: nowIso };
  const fields = ['updatedAt'];
  for (const k of allowed) if (set[k] !== undefined) { doc[k] = set[k]; fields.push(k); }
  if (p.note) { doc.lastNote = String(p.note); if (!fields.includes('lastNote')) fields.push('lastNote'); }
  if (fields.length === 1) return err('update_ticket: nothing to update. Allowed: ' + allowed.join(', '));
  return out({ __kind: 'update', __collection: 'tickets', __updateKey: 'ticketId', __fields: fields.join(','), ...doc });
}
if (op === 'advance_claim') {
  if (!p.claimId) return err('advance_claim needs claimId');
  const stages = ['documents_required', 'under_review', 'company_email_sent', 'amount_claimed', 'amount_verification', 'shortfall_requery', 'settled', 'closed'];
  const doc = { claimId: String(p.claimId), updatedAt: nowIso };
  const fields = ['updatedAt'];
  if (p.stage) { if (!stages.includes(p.stage)) return err('Invalid stage. Valid: ' + stages.join(' -> ')); doc.stage = p.stage; fields.push('stage'); if (p.stage === 'settled' || p.stage === 'closed') { doc.status = p.stage === 'closed' ? 'closed' : 'settled'; fields.push('status'); } }
  if (typeof p.amounts === 'object' && p.amounts) { doc.amounts = p.amounts; fields.push('amounts'); }
  if (p.note) { doc.lastNote = String(p.note); fields.push('lastNote'); }
  if (fields.length === 1) return err('advance_claim: provide stage, amounts or note');
  return out({ __kind: 'update', __collection: 'claims', __updateKey: 'claimId', __fields: fields.join(','), ...doc });
}
if (op === 'counts' || op === 'get_counts') {
  const type = ['claims', 'tickets', 'leads', 'clients'].includes(p.type) ? p.type : 'tickets';
  const groupField = type === 'claims' ? 'stage' : (type === 'leads' ? 'stage' : (type === 'clients' ? 'isActive' : 'state'));
  const proj = {}; proj[groupField] = 1;
  return out({ __kind: 'counts', __collection: type, __query: (typeof p.query === 'object' && p.query) || {}, __limit: 100000, __type: type, __groupField: groupField, __projection: proj });
}
return err('Unknown operation: ' + op + '. Valid: find_client, get_policies, get_ticket, get_claim, ticket_guard, paginate, crm_list, team_ops, create_lead, get_documents, create_ticket, create_claim, update_ticket, advance_claim, counts, get_counts');

const rows = $input.all().map(i => i.json).filter(j => j && Object.keys(j).length > 0);
const clean = rows.map(r => { const c = { ...r }; if (c._id) c._id = String(c._id); return c; });
const meta = $('Route Operation').first().json;
const res = { ok: true, count: clean.length, results: clean };
if (meta.__page) { res.page = meta.__page; res.pageSize = meta.__limit || 5; res.hint = clean.length === (meta.__limit || 5) ? 'There may be more results on page ' + (meta.__page + 1) : 'No more pages.'; }
if (clean.length === 0) res.hint = 'No records found. Try different spelling or another identifier.';
return [{ json: res }];

const d = $('Route Operation').first().json;
const id = d.ticketId || d.claimId || d.leadId || d.taskId || null;
const summary = { ok: true, created: true, id, collection: d.__collection };
if (d.ticketId) { summary.ticketId = d.ticketId; summary.state = d.state; summary.category = d.category; summary.priority = d.priority; }
if (d.claimId) { summary.claimId = d.claimId; summary.stage = d.stage; summary.claimType = d.claimType; summary.policyNo = d.policyNo; }
if (d.leadId) { summary.leadId = d.leadId; summary.name = d.name; summary.stage = d.stage; summary.interest = d.interest; }
if (d.taskId) { summary.taskId = d.taskId; summary.title = d.title; summary.assigneeName = d.assigneeName; summary.dueAt = d.dueAt; summary.type = d.type; }
return [{ json: summary }];

const d = $('Route Operation').first().json;
const changed = {};
for (const k of String(d.__fields || '').split(',')) if (k && d[k] !== undefined) changed[k] = d[k];
return [{ json: { ok: true, updated: true, id: d.ticketId || d.claimId, collection: d.__collection, changes: changed } }];

const meta = $('Route Operation').first().json;
const field = meta.__groupField || 'state';
const type = meta.__type || 'tickets';
const rows = $input.all().map(i => i.json).filter(j => j && Object.keys(j).length > 0);
const byStatus = {};
for (const r of rows) { const k = String(r[field] == null ? 'unknown' : r[field]); byStatus[k] = (byStatus[k]||0)+1; }
const total = rows.length;
const closedish = ['closed','resolved','settled'];
let open = 0; for (const e of Object.entries(byStatus)) if (!closedish.includes(e[0])) open += e[1];
return [{ json: { ok:true, type, groupBy: field, total, open, byStatus } }];
